/* Black Atom Industries — Design System */

:root {
	--ink: oklch(0.26 0 0);
	--paper: oklch(0.92 0.032 89);

	--ink-90: color-mix(in oklch, var(--ink) 90%, transparent);
	--ink-70: color-mix(in oklch, var(--ink) 70%, transparent);
	--ink-60: color-mix(in oklch, var(--ink) 60%, transparent);
	--ink-40: color-mix(in oklch, var(--ink) 40%, transparent);
	--ink-30: color-mix(in oklch, var(--ink) 30%, transparent);
	--ink-20: color-mix(in oklch, var(--ink) 20%, transparent);
	--ink-10: color-mix(in oklch, var(--ink) 10%, transparent);
	--ink-05: color-mix(in oklch, var(--ink) 5%, transparent);

	--paper-80: color-mix(in oklch, var(--paper) 80%, transparent);
	--paper-75: color-mix(in oklch, var(--paper) 75%, transparent);
	--paper-60: color-mix(in oklch, var(--paper) 60%, transparent);
	--paper-50: color-mix(in oklch, var(--paper) 50%, transparent);
	--paper-35: color-mix(in oklch, var(--paper) 35%, transparent);
	--paper-30: color-mix(in oklch, var(--paper) 30%, transparent);

	--font-display: "Archivo Black", "Helvetica Neue", Impact, sans-serif;
	--font-mono: "JetBrains Mono", ui-monospace, monospace;

	--space-xs: 4px;
	--space-sm: 8px;
	--space-md: 16px;
	--space-lg: 32px;
	--space-xl: 48px;
	--space-2xl: 80px;

	--stroke: 1px solid var(--ink);
	--stroke-muted: 1px solid var(--ink-20);
}

*,
*::before,
*::after {
	box-sizing: border-box;
}

html,
body {
	margin: 0;
	padding: 0;
	background: var(--paper);
	color: var(--ink);
	font-family: var(--font-mono);
	font-size: 14px;
	line-height: 1.55;
	-webkit-font-smoothing: antialiased;
	-moz-osx-font-smoothing: grayscale;
}

h1,
h2,
h3,
h4,
h5,
h6 {
	margin: 0;
	font-family: var(--font-display);
	text-transform: uppercase;
	font-weight: 400;
}

p {
	margin: 0 0 1em;
	color: var(--ink-70);
}

p:last-child {
	margin-bottom: 0;
}

a {
	color: var(--ink);
	text-decoration: none;
}

strong {
	font-weight: 700;
	color: var(--ink);
}

